diff --git a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
index 4a014ab6e044..bdd6e187b63f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
@@ -1561,6 +1561,15 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
       Value *And = Builder.CreateAnd(BoolX, BoolY);
       return new ZExtInst(And, Ty);
     }
+
+    // (X & 1) + (Y & 1) >> 1 --> (X & 1) & Y
+    // This is the carry bit when adding two LSBs, which is 1 iff both are 1.
+    if (ShAmtC == 1 &&
+        match(Op0, m_c_Add(m_c_And(m_Value(X), m_SpecificInt(1)),
+                           m_c_And(m_Value(Y), m_SpecificInt(1))))) {
+      Value *XAnd1 = Builder.CreateAnd(X, ConstantInt::get(Ty, 1));
+      return BinaryOperator::CreateAnd(XAnd1, Y);
+    }
   }

   const SimplifyQuery Q = SQ.getWithInstruction(&I);

